import{c as e,Q as t,j as i,m as r}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"Tags and audio writes","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tags-and-audio-writes.md","filePath":"user-guide/tags-and-audio-writes.md","lastUpdated":null}'),s={name:"user-guide/tags-and-audio-writes.md"};function o(n,a,d,l,h,c){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="tags-and-audio-writes" tabindex="-1">Tags and audio writes <a class="header-anchor" href="#tags-and-audio-writes" aria-label="Permalink to &quot;Tags and audio writes&quot;">​</a></h1><p>Audience: careful users and power users<br> Goal: understand the explicit tag-writing exception<br> Type: how-to</p><p>Most app workflows are read-only toward source audio. Genre tag writing is the intentional exception: it can write stored MAEST genre labels into standard audio genre tags.</p><h2 id="what-can-write-tags" tabindex="-1">What can write tags <a class="header-anchor" href="#what-can-write-tags" aria-label="Permalink to &quot;What can write tags&quot;">​</a></h2><p>The explicit app path is:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /api/tags/genres/apply</span></span></code></pre></div><p>or the matching UI job.</p><p>It writes only the standard genre field from stored MAEST labels. It should preserve title, artist, album, BPM, key, and other normal tags.</p><h2 id="formats" tabindex="-1">Formats <a class="header-anchor" href="#formats" aria-label="Permalink to &quot;Formats&quot;">​</a></h2><p>The tag-writing code uses standard fields:</p><ul><li><code>TCON</code> for MP3/WAV/AIFF ID3;</li><li><code>GENRE</code> for FLAC/Vorbis-style tags;</li><li><code>©gen</code> for MP4/M4A/ALAC.</li></ul><h2 id="batch-behavior" tabindex="-1">Batch behavior <a class="header-anchor" href="#batch-behavior" aria-label="Permalink to &quot;Batch behavior&quot;">​</a></h2><p>Failed writes should fail that track and let the batch continue. For WAV, the app uses Mutagen WAVE/ID3 handling and reads back <code>TCON</code>; it does not add custom RIFF repair logic to the tag-writing path.</p><h2 id="before-writing-tags" tabindex="-1">Before writing tags <a class="header-anchor" href="#before-writing-tags" aria-label="Permalink to &quot;Before writing tags&quot;">​</a></h2><p>Make sure:</p><ul><li>MAEST labels are present and worth writing;</li><li>you have backups if the files matter;</li><li>you understand this is not the same workflow as search, analysis, preview, or export.</li></ul>',16)])])}const g=e(s,[["render",o]]);export{u as __pageData,g as default};
